using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false
        }
    };

    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/features",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns the current feature flag values.")]
    public static string GetFeatureFlags() =>
        JsonSerializer.Serialize(AppConfig["features"], new JsonSerializerOptions { WriteIndented = true });
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Looks up an environment variable by name and returns its value.")]
    public static string GetEnvVariable(
        [Description("The environment variable name to look up")] string name)
    {
        var value = Environment.GetEnvironmentVariable(name);
        return value is not null
            ? $"{name}={value}"
            : $"Environment variable '{name}' is not set.";
    }

    [McpServerTool, Description("Returns the current server UTC time and .NET runtime version.")]
    public static string GetServerInfo() =>
        $"UTC: {DateTime.UtcNow:O} | Runtime: {Environment.Version}";
}

